import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

export default function Navbar() {
  const { user, logout, API } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const [unread, setUnread] = useState(0);

  useEffect(() => {
    const fetchUnread = async () => {
      try {
        const { data } = await axios.get(`${API}/notifications`);
        setUnread(data.filter(n => !n.read).length);
      } catch {}
    };
    fetchUnread();
    const interval = setInterval(fetchUnread, 30000);
    return () => clearInterval(interval);
  }, [API]);

  const nav = [
    { path: '/dashboard', label: 'Dashboard', icon: '⊞' },
    { path: '/projects', label: 'Projects', icon: '🗂' },
    ...(user && user.role === 'student' ? [{ path: '/achievements', label: 'Achievements', icon: '🏆' }] : []),
    ...(user && user.role !== 'student' ? [{ path: '/students', label: 'Students', icon: '👥' }] : []),
    { path: '/requests', label: 'Requests', icon: '📬' },
    { path: '/notifications', label: 'Alerts', icon: '🔔', badge: unread },
    { path: '/profile', label: 'Profile', icon: '👤' },
  ];

  const handleLogout = () => { logout(); navigate('/login'); };
  const initials = user ? user.name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0,2) : 'U';

  return (
    <nav style={{display:'flex',alignItems:'center',padding:'0 1.5rem',height:'60px',background:'#0f1320',borderBottom:'1px solid #252d47',position:'sticky',top:0,zIndex:100,gap:'1.5rem'}}>
      <Link to="/dashboard" style={{display:'flex',alignItems:'center',gap:'10px',textDecoration:'none',flexShrink:0}}>
        <div style={{width:36,height:36,borderRadius:10,background:'linear-gradient(135deg, #6c63ff, #00d4aa)',display:'flex',alignItems:'center',justifyContent:'center',color:'#fff',fontSize:'1.1rem',flexShrink:0}}>⟡</div>
        <div>
          <div style={{fontWeight:900,fontSize:'0.85rem',color:'#6c63ff',lineHeight:1,letterSpacing:'0.05em'}}>SIST</div>
          <div style={{fontWeight:700,fontSize:'0.85rem',color:'#e8eaf0',lineHeight:1.2,letterSpacing:'-0.3px'}}>SkillConnect</div>
        </div>
      </Link>

      <div style={{display:'flex',gap:'0.25rem',flex:1}}>
        {nav.map(item => (
          <Link key={item.path} to={item.path} style={{display:'flex',alignItems:'center',gap:'6px',padding:'6px 12px',borderRadius:8,color:location.pathname===item.path?'#6c63ff':'#9aa3bf',background:location.pathname===item.path?'rgba(108,99,255,0.15)':'transparent',fontSize:'0.825rem',fontWeight:500,textDecoration:'none',position:'relative',whiteSpace:'nowrap'}}>
            <span style={{fontSize:'0.9rem'}}>{item.icon}</span>
            <span>{item.label}</span>
            {item.badge > 0 && <span style={{background:'#ff6b9d',color:'#fff',borderRadius:99,padding:'1px 5px',fontSize:'0.65rem',fontWeight:700,minWidth:16,textAlign:'center'}}>{item.badge}</span>}
          </Link>
        ))}
      </div>

      <div style={{display:'flex',alignItems:'center',gap:'0.75rem',flexShrink:0}}>
        <div style={{width:34,height:34,borderRadius:'50%',background:'linear-gradient(135deg, #ff6b9d, #6c63ff)',display:'flex',alignItems:'center',justifyContent:'center',color:'#fff',fontWeight:700,fontSize:'0.75rem',flexShrink:0}}>{initials}</div>
        <div style={{textAlign:'right'}}>
          <div style={{fontWeight:600,fontSize:'0.8rem',color:'#e8eaf0',maxWidth:120,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{user && user.name}</div>
          <div style={{fontSize:'0.65rem',color:'#6c63ff',fontWeight:600}}>{user && user.role && user.role.toUpperCase()}</div>
        </div>
        <button onClick={handleLogout} style={{padding:'5px 12px',borderRadius:7,border:'1px solid #252d47',background:'transparent',color:'#9aa3bf',fontSize:'0.8rem',cursor:'pointer',whiteSpace:'nowrap'}}>Logout</button>
      </div>
    </nav>
  );
}
